import React from "react";
import { Link } from "react-router-dom";

import img from "../images/indexbg.jpg";
import logo from "../images/logo1.png";

export default function Home() {
  return (
    <div
      className="container d-flex align-items-center justify-content-center text-center flex-column text-dark"
      style={{
        height: "120vh",
    
        backgroundImage: `linear-gradient(rgba(0,0,0,0.5), rgba(0,0,0,0.5)), url(${img})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
      }}
    >
      <img src={logo} alt="Restaurant Logo" width="200px" />
      <div className="bg-transparent p-5 rounded shadow-lg">
        <h1 className="display-4 fw-bold text-white">Best food for your taste</h1>
        <p className="lead my-3 text-white">
          Discover delectable cuisine and unforgettable moments in our
          welcoming, culinary haven.
        </p>
        <div>
          <Link to="/Login" className="btn bg-success text-white btn-lg">
            Explore Menu
          </Link>
        </div>
      </div>
    </div>
  );
}
